#include <iostream>

using namespace std;

class Invoice
{
private:
    double subtotal;

    double calculateTax() // complex detail, hidden
    {
        return subtotal * 0.08;
    }

    double calculateDiscount() // complex detail, hidden
    {
        return subtotal > 100 ? subtotal * 0.1 : 0;
    }

public:
    Invoice(double amount)
    {
        subtotal = amount;
    }

    double getTotal() // the ONLY thing a user actually needs
    {
        return subtotal + calculateTax() - calculateDiscount();
    }
};

int main()
{
    Invoice inv(200);

    cout << inv.getTotal() << endl;

    return 0;
}

